#!/usr/bin/perl
use strict;
use warnings;

while (<>) {
    # Fix .Init() with no args on store variables
    s/(\bstore\b|\bs\b)\.Init\(\)/$1.Init(context.Background())/g;
    s/\bspokeStore\.Init\(\)/spokeStore.Init(context.Background())/g;

    # Fix .ReadAll() with no args
    s/(\bstore\b|\bs\b)\.ReadAll\(\)/$1.ReadAll(context.Background())/g;

    # Fix .Get(expr) where expr doesn't start with context
    # Match store.Get( followed by a non-context arg
    s/(\bstore\b|\bs\b|\bspokeStore\b)\.Get\((?!context\.)([^,)]+)\)/$1.Get(context.Background(), $2)/g;

    # Fix .Create(b) where b is exactly 'b'
    s/(\bstore\b|\bs\b)\.Create\(b\)/$1.Create(context.Background(), b)/g;
    # Fix .Create(&bead.Bead{ - don't add closing paren
    s/(\bstore\b|\bs\b)\.Create\((&[^,)]+\{)/$1.Create(context.Background(), $2/g;

    # Fix .Update(id, func( - match "store.Update(somevar, func("
    # where somevar doesn't contain context
    s/(\bstore\b|\bs\b)\.Update\((?!context\.)([^,]+), func\(/$1.Update(context.Background(), $2, func(/g;

    # Fix .Close(id) where id is a simple var
    s/(\bstore\b|\bs\b)\.Close\((?!context\.)([^,)]+)\)/$1.Close(context.Background(), $2)/g;

    print;
}
